package com.example.auth

import android.content.Context
import android.content.SharedPreferences
import androidx.annotation.MainThread
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow

data class AuthSession(
    val userId: String,
    val authToken: String
)

class AuthManager(context: Context) {

    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_USER_ID = "key_user_id"
        private const val KEY_AUTH_TOKEN = "key_auth_token"
    }

    private val prefs: SharedPreferences =
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    private val _sessionState = MutableStateFlow(loadSession())
    val sessionState: StateFlow<AuthSession?> = _sessionState.asStateFlow()

    val isLoggedIn: Boolean
        get() = _sessionState.value != null

    fun getCurrentSession(): AuthSession? = _sessionState.value

    @MainThread
    fun saveLogin(userId: String, authToken: String) {
        prefs.edit()
            .putString(KEY_USER_ID, userId)
            .putString(KEY_AUTH_TOKEN, authToken)
            .apply()

        _sessionState.value = AuthSession(userId = userId, authToken = authToken)
    }

    @MainThread
    fun clearLogin() {
        prefs.edit()
            .remove(KEY_USER_ID)
            .remove(KEY_AUTH_TOKEN)
            .apply()

        _sessionState.value = null
    }

    private fun loadSession(): AuthSession? {
        val userId = prefs.getString(KEY_USER_ID, null)
        val authToken = prefs.getString(KEY_AUTH_TOKEN, null)

        return if (!userId.isNullOrBlank() && !authToken.isNullOrBlank()) {
            AuthSession(userId = userId, authToken = authToken)
        } else {
            null
        }
    }
}